#include<bits/stdc++.h>
using namespace std;
const double eps=1e-6;
vector<int> mp[100010];
int dfncnt,dfn[100010],rnk[100010];
int k,n,cost[100010],siz[100010],val[100010];
void dfs(int x)
{
    siz[x]=1;
    for(int i:mp[x])
    {
        dfs(i);
        siz[x]+=siz[i];
    }
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
}
double v[100010],f[5050][5050];
bool check(double mid)
{
    for(int i=0;i<=dfncnt;i++)
    {
        for(int j=1;j<=k;j++)
        {
            f[i][j]=-1e12;
        }
    }
    for(int i=1;i<=n;i++)
    {
        v[i]=1.0*val[i]-mid*cost[i];
    }
    for(int i=1;i<=dfncnt;i++)
    {
        for(int j=1;j<=k;j++)
        {
            f[i][j]=max(f[i-1][j-1]+v[rnk[i]],f[i-siz[rnk[i]]][j]);
        }
    }
    return f[dfncnt][k]>0;
}
int main()
{
    scanf("%d%d",&k,&n);
    k++;
    for(int i=1;i<=n;i++)
    {
        int fa;
        scanf("%d%d%d",&cost[i],&val[i],&fa);
        mp[fa].push_back(i);
    }
    dfs(0);
    double l=0,r=1e5;
    while(r-l>=eps)
    {
        double mid=(l+r)/2.0;
        if(check(mid))
        {
            l=mid;
        }
        else
        {
            r=mid;
        }
    }
    printf("%.3lf",l);
    return 0;
}
